import io.grpc.Metadata;
import io.grpc.Status;
import io.grpc.StatusRuntimeException;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Service
public class GrpcTokenExtractor {
    public static final Metadata.Key<String> AUTH_KEY =
        Metadata.Key.of("authorization", Metadata.ASCII_STRING_MARSHALLER);
    public static final Metadata.Key<String> MERCHANT_KEY =
        Metadata.Key.of("x-merchant-id", Metadata.ASCII_STRING_MARSHALLER);

    public String extractToken(Metadata headers) {
        String authHeader = headers.get(AUTH_KEY);
        if (authHeader == null) {
            throw new StatusRuntimeException(
                Status.UNAUTHENTICATED.withDescription("Authorization header is required"));
        }
        if (!authHeader.startsWith("Bearer ")) {
            throw new StatusRuntimeException(
                Status.UNAUTHENTICATED.withDescription("Bearer token format required"));
        }
        return authHeader.substring(7); // strip 'Bearer '
    }

    public String extractMerchantId(Metadata headers) {
        String merchantId = headers.get(MERCHANT_KEY);
        if (merchantId == null || merchantId.isBlank()) {
            throw new StatusRuntimeException(
                Status.UNAUTHENTICATED.withDescription("x-merchant-id header required"));
        }
        return merchantId;
    }
}

@SpringBootTest
class TokenExtractorTest {
    @Autowired GrpcTokenExtractor extractor;

    @Test void validBearer_extractsToken() {
        Metadata headers = new Metadata();
        headers.put(GrpcTokenExtractor.AUTH_KEY, "Bearer rzp_live_abc123");
        assertEquals("rzp_live_abc123", extractor.extractToken(headers));
    }
    @Test void missingHeader_throwsUnauthenticated() {
        Metadata headers = new Metadata();
        var ex = assertThrows(StatusRuntimeException.class,
            () -> extractor.extractToken(headers));
        assertEquals(Status.Code.UNAUTHENTICATED, ex.getStatus().getCode());
    }
    @Test void wrongFormat_throwsUnauthenticated() {
        Metadata headers = new Metadata();
        headers.put(GrpcTokenExtractor.AUTH_KEY, "Basic abc123"); // not Bearer
        var ex = assertThrows(StatusRuntimeException.class,
            () -> extractor.extractToken(headers));
        assertTrue(ex.getStatus().getDescription().contains("Bearer"));
    }
}

import io.grpc.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;

@Service
public class JwtServerInterceptor implements ServerInterceptor {
    private static final Metadata.Key<String> AUTH =
        Metadata.Key.of("authorization", Metadata.ASCII_STRING_MARSHALLER);

    // Simulated valid tokens (production: use JwtDecoder)
    private final Set<String> validTokens = new HashSet<>(Set.of(
        "rzp_valid_merchant_token",
        "hdfc_internal_service_token"
    ));

    @Override
    public <Q, R> ServerCall.Listener<Q> interceptCall(
            ServerCall<Q, R> call, Metadata headers, ServerCallHandler<Q, R> next) {

        String authHeader = headers.get(AUTH);

        // 1. Check presence:
        if (authHeader == null || !authHeader.startsWith("Bearer ")) {
            call.close(Status.UNAUTHENTICATED
                .withDescription("Bearer token required in 'authorization' metadata"),
                new Metadata());
            return new ServerCall.Listener<>() {}; // abort: no further processing
        }

        // 2. Validate token:
        String token = authHeader.substring(7);
        if (!validTokens.contains(token)) {
            call.close(Status.UNAUTHENTICATED
                .withDescription("Token is invalid or expired"),
                new Metadata());
            return new ServerCall.Listener<>() {};
        }

        // 3. Valid: pass to actual handler:
        return next.startCall(call, headers);
    }

    // Test helper: add valid token
    public void addValidToken(String token) { validTokens.add(token); }

    // Check if a token would be accepted:
    public boolean wouldAccept(String bearerHeader) {
        if (bearerHeader == null || !bearerHeader.startsWith("Bearer ")) return false;
        return validTokens.contains(bearerHeader.substring(7));
    }
}

@SpringBootTest
class JwtInterceptorTest {
    @Autowired JwtServerInterceptor interceptor;

    @Test void validToken_accepted() {
        assertTrue(interceptor.wouldAccept("Bearer rzp_valid_merchant_token"));
    }
    @Test void invalidToken_rejected() {
        assertFalse(interceptor.wouldAccept("Bearer rzp_INVALID_token"));
    }
}

