import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;

// Simulated token: 'role:merchantId' format for tests
// Production: decode JWT claims
@Service
public class RbacInterceptor {

    enum Role { MERCHANT, ADMIN, SERVICE }

    // Admin-only RPC methods:
    private static final Set<String> ADMIN_ONLY = Set.of(
        "PaymentService/ListAllMerchants",
        "PaymentService/DisableMerchant",
        "PaymentService/ViewAllTransactions"
    );

    record AuthContext(String merchantId, Role role) {}

    public AuthContext extractContext(String bearerToken) {
        // Token format: 'ROLE:merchantId' (e.g. 'MERCHANT:MRC-001', 'ADMIN:STAFF-01')
        if (bearerToken == null) throw new StatusRuntimeException(
            Status.UNAUTHENTICATED.withDescription("Token required"));
        String[] parts = bearerToken.split(":", 2);
        if (parts.length != 2) throw new StatusRuntimeException(
            Status.UNAUTHENTICATED.withDescription("Invalid token format"));
        try {
            Role role = Role.valueOf(parts[0].toUpperCase());
            return new AuthContext(parts[1], role);
        } catch (IllegalArgumentException e) {
            throw new StatusRuntimeException(
                Status.UNAUTHENTICATED.withDescription("Unknown role: " + parts[0]));
        }
    }

    public void checkAuthorization(AuthContext ctx, String fullMethodName) {
        if (ADMIN_ONLY.contains(fullMethodName) && ctx.role() != Role.ADMIN) {
            throw new StatusRuntimeException(
                Status.PERMISSION_DENIED.withDescription(
                    "Method " + fullMethodName + " requires ADMIN role, got: " + ctx.role()));
        }
    }
}

@SpringBootTest
class RbacInterceptorTest {
    @Autowired RbacInterceptor rbac;

    @Test void merchant_canAccessMerchantMethod() {
        var ctx = rbac.extractContext("MERCHANT:MRC-001");
        assertEquals(RbacInterceptor.Role.MERCHANT, ctx.role());
        assertDoesNotThrow(() -> rbac.checkAuthorization(ctx, "PaymentService/CreatePayment"));
    }
    @Test void merchant_cannotAccessAdminMethod() {
        var ctx = rbac.extractContext("MERCHANT:MRC-001");
        var ex = assertThrows(StatusRuntimeException.class,
            () -> rbac.checkAuthorization(ctx, "PaymentService/ListAllMerchants"));
        assertEquals(Status.Code.PERMISSION_DENIED, ex.getStatus().getCode());
    }
    @Test void admin_canAccessAdminMethod() {
        var ctx = rbac.extractContext("ADMIN:STAFF-01");
        assertEquals(RbacInterceptor.Role.ADMIN, ctx.role());
        assertDoesNotThrow(() -> rbac.checkAuthorization(ctx, "PaymentService/ListAllMerchants"));
    }
}

