    public static final Metadata.Key<String> MERCHANT_KEY =
        Metadata.Key.of("x-merchant-id", Metadata.ASCII_STRING_MARSHALLER);

    // Option 1: Per-call metadata (most flexible):
    public ClientInterceptor buildBearerInterceptor(String token) {
        Metadata headers = new Metadata();
        headers.put(AUTH_KEY, "Bearer " + token);
        return MetadataUtils.newAttachHeadersInterceptor(headers);
    }

    // Option 2: CallCredentials (gRPC-native, supports token refresh):
    public CallCredentials buildCallCredentials(String token) {
        return new CallCredentials() {
            @Override
            public void applyRequestMetadata(RequestInfo requestInfo, Executor appExecutor, MetadataApplier applier) {
                Metadata metadata = new Metadata();
                metadata.put(AUTH_KEY, "Bearer " + token);
                applier.apply(metadata); // async-safe: called per RPC
            }
        };
    }

    // Build channel with TLS + auth:
    // ManagedChannel channel = Grpc.newChannelBuilderForAddress(host, port, TlsChannelCredentials.create())
    //     .build();
    // Stub stub = PaymentServiceGrpc.newBlockingStub(channel)
    //     .withCallCredentials(buildCallCredentials(token))
    //     .withInterceptors(buildBearerInterceptor(token)); // OR interceptor approach

    // Helper for tests:
    public Metadata buildHeaders(String token, String merchantId) {
        Metadata h = new Metadata();
        h.put(AUTH_KEY, "Bearer " + token);
        h.put(MERCHANT_KEY, merchantId);
        return h;
    }
}

