import io.grpc.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

// Authentication context (set by interceptor, read by service):
record AuthContext(String merchantId, String role) {}

// Context key: thread-local-like storage for gRPC
@Service
public class GrpcContextHolder {
    public static final Context.Key<AuthContext> AUTH_CONTEXT =
        Context.key("auth-context");

    // Set in interceptor:
    public Context withAuthContext(Context ctx, AuthContext auth) {
        return ctx.withValue(AUTH_CONTEXT, auth);
    }

    // Get in service method:
    public AuthContext getCurrentAuth() {
        AuthContext ctx = AUTH_CONTEXT.get();
        if (ctx == null) {
            throw new StatusRuntimeException(
                Status.INTERNAL.withDescription("Auth context not set — missing interceptor?"));
        }
        return ctx;
    }

    // Simulate what interceptor does:
    public <T> T runWithAuth(AuthContext auth, java.util.concurrent.Callable<T> action) throws Exception {
        Context ctx = Context.current().withValue(AUTH_CONTEXT, auth);
        Context previous = ctx.attach();
        try {
            return action.call();
        } finally {
            ctx.detach(previous);
        }
    }
}

@Service
class PaymentServiceWithAuth {
    private final GrpcContextHolder holder;
    PaymentServiceWithAuth(GrpcContextHolder h) { holder = h; }

    // Called by gRPC handler inside Context set by interceptor:
    public String processPayment(long amountPaise) {
        AuthContext auth = holder.getCurrentAuth();
        return "Payment of ₹" + amountPaise/100 + " processed for merchant: " + auth.merchantId();
    }
}

@SpringBootTest
class ContextPropagationTest {
    @Autowired GrpcContextHolder holder;
    @Autowired PaymentServiceWithAuth paymentService;

    @Test void authContext_propagatedToService() throws Exception {
        AuthContext auth = new AuthContext("MRC-001", "MERCHANT");
        String result = holder.runWithAuth(auth, () -> paymentService.processPayment(50000L));
        assertTrue(result.contains("MRC-001"));
        assertTrue(result.contains("500"));
    }
    @Test void missingContext_throwsInternal() {
        // Without interceptor setting context: getCurrentAuth() throws INTERNAL
        // (Context is not set — programming error, not auth failure)
        assertThrows(StatusRuntimeException.class, () -> holder.getCurrentAuth());
    }
}

