import io.grpc.*;
import io.github.bucket4j.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.time.Duration;
import java.util.concurrent.ConcurrentHashMap;
import java.util.Map;

@Service
public class GrpcRateLimitInterceptor {
    private static final Metadata.Key<String> MERCHANT_KEY =
        Metadata.Key.of("x-merchant-id", Metadata.ASCII_STRING_MARSHALLER);

    private final Map<String, Bucket> buckets = new ConcurrentHashMap<>();

    private Bucket getBucket(String merchantId) {
        return buckets.computeIfAbsent(merchantId, k ->
            Bucket.builder()
                .addLimit(Bandwidth.classic(100, Refill.greedy(100, Duration.ofMinutes(1))))
                .build());
    }

    public boolean allowRequest(String merchantId) {
        return getBucket(merchantId).tryConsume(1);
    }

    public long availableTokens(String merchantId) {
        return getBucket(merchantId).getAvailableTokens();
    }

    // Interceptor logic (how it would be used in full interceptor):
    public <Q, R> void checkRateLimit(ServerCall<Q, R> call, Metadata headers) {
        String merchantId = headers.get(MERCHANT_KEY);
        if (merchantId == null) merchantId = "anonymous";

        if (!allowRequest(merchantId)) {
            call.close(Status.RESOURCE_EXHAUSTED
                .withDescription("Rate limit exceeded for merchant: " + merchantId +
                    ". Max 100 RPCs/minute. Retry after 60s."),
                new Metadata());
        }
    }
}

@SpringBootTest
class GrpcRateLimitTest {
    @Autowired GrpcRateLimitInterceptor rateLimiter;

    @Test void withinLimit_allowed() {
        String merchant = "MRC-RL-" + System.nanoTime();
        assertTrue(rateLimiter.allowRequest(merchant));
        assertEquals(99, rateLimiter.availableTokens(merchant)); // 1 consumed
    }
    @Test void exceededLimit_blocked() {
        String merchant = "MRC-EXHAUST-" + System.nanoTime();
        // Exhaust all 100 tokens:
        for (int i = 0; i < 100; i++) rateLimiter.allowRequest(merchant);
        // 101st request blocked:
        assertFalse(rateLimiter.allowRequest(merchant));
        assertEquals(0, rateLimiter.availableTokens(merchant));
    }
}

