import org.junit.jupiter.api.*;
import java.time.Duration;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

record CallCtx(String merchantId, String role) {}

@Service class CompleteRateLimit {
    private final Map<String,Bucket> b=new ConcurrentHashMap<>();
    Bucket get(String m){return b.computeIfAbsent(m,k->Bucket.builder().addLimit(Bandwidth.classic(100,Refill.greedy(100,Duration.ofMinutes(1)))).build());}
    boolean allow(String m){return get(m).tryConsume(1);}
    void exhaust(String m){while(get(m).tryConsume(1));}
}

@Service class CompleteAuth {
    private final Set<String> valid=new HashSet<>(Set.of("MERCHANT:MRC-001","ADMIN:ADM-001","MERCHANT:MRC-002"));
    CallCtx validate(String bearer){
        if(bearer==null) throw new StatusRuntimeException(Status.UNAUTHENTICATED.withDescription("token required"));
        String token=bearer.startsWith("Bearer ")?bearer.substring(7):bearer;
        if(!valid.contains(token)) throw new StatusRuntimeException(Status.UNAUTHENTICATED.withDescription("invalid token"));
        String[] p=token.split(":",2); return new CallCtx(p[1],p[0]);
    }
}

@Service class CompleteRbac {
    private final Set<String> adminOnly=Set.of("ListAllMerchants","DisableMerchant");
    void check(CallCtx ctx,String method){
        if(adminOnly.contains(method)&&!"ADMIN".equals(ctx.role()))
            throw new StatusRuntimeException(Status.PERMISSION_DENIED.withDescription("ADMIN required"));
    }
}

@SpringBootTest
class CompleteAuthStackTest {
    @Autowired CompleteRateLimit rl;
    @Autowired CompleteAuth auth;
    @Autowired CompleteRbac rbac;

    @Test void rateLimit_exhausted_blocks(){
        rl.exhaust("MRC-EXHAUST");
        assertFalse(rl.allow("MRC-EXHAUST"));
    }
    @Test void invalidToken_unauthenticated(){
        var ex=assertThrows(StatusRuntimeException.class,()->auth.validate("Bearer invalid_xyz"));
        assertEquals(Status.Code.UNAUTHENTICATED,ex.getStatus().getCode());
    }
    @Test void merchantAccessingAdminMethod_permissionDenied(){
        CallCtx ctx=auth.validate("Bearer MERCHANT:MRC-001");
        var ex=assertThrows(StatusRuntimeException.class,()->rbac.check(ctx,"ListAllMerchants"));
        assertEquals(Status.Code.PERMISSION_DENIED,ex.getStatus().getCode());
    }
    @Test void admin_fullHappyPath(){
        assertTrue(rl.allow("ADM-001"));
        CallCtx ctx=auth.validate("Bearer ADMIN:ADM-001");
        assertEquals("ADMIN",ctx.role());
        assertDoesNotThrow(()->rbac.check(ctx,"ListAllMerchants"));
    }
}

