// In mTLS: client presents a TLS certificate
// The server extracts identity from the cert's CN or SAN
// No separate JWT needed — the certificate IS the identity

record ServiceIdentity(String serviceName, String pod, String namespace) {
    // Parse from certificate CN format: 'service-name.pod-id.namespace'
    static ServiceIdentity parse(String cn) {
        if (cn == null || cn.isBlank())
            throw new IllegalArgumentException("Empty certificate CN");
        String[] parts = cn.split("\\.", 3);
        if (parts.length < 2)
            throw new IllegalArgumentException("Invalid CN format: " + cn);
        String service = parts[0];
        String pod = parts.length > 1 ? parts[1] : "unknown";
        String ns = parts.length > 2 ? parts[2] : "default";
        return new ServiceIdentity(service, pod, ns);
    }
    boolean isValid() { return serviceName != null && !serviceName.isBlank(); }
}

@Service
public class ServiceAuthValidator {
    // Allowed internal services (Razorpay's service mesh):
    private static final Set<String> ALLOWED_SERVICES = Set.of(
        "payment-service",
        "fraud-service",
        "settlement-service",
        "notification-service",
        "analytics-service"
    );

    public void validate(String certificateCN) {
        ServiceIdentity identity;
        try {
            identity = ServiceIdentity.parse(certificateCN);
        } catch (IllegalArgumentException e) {
            throw new StatusRuntimeException(
                Status.UNAUTHENTICATED.withDescription("Invalid certificate CN: " + certificateCN));
        }

        if (!ALLOWED_SERVICES.contains(identity.serviceName())) {
            throw new StatusRuntimeException(
                Status.PERMISSION_DENIED.withDescription(
                    "Service '" + identity.serviceName() + "' is not authorized to call this API"));
        }
    }

    public boolean isAllowed(String serviceName) {
        return ALLOWED_SERVICES.contains(serviceName);
    }
}

